sql:
SELECT station_id, station_name, location, COUNT(*) OVER() AS total_count
FROM weather_stations
WHERE elevation > 2000;

SELECT u.user_name, u.email, dh.change_date, dh.changed_by
FROM users u
INNER JOIN data_history dh ON u.user_name = dh.changed_by;

SELECT parameter_name, unit
FROM parameters
WHERE parameter_id > 5;

external_knowledge:
- "sailors" refers to the users;
- "holding their ship’s charts" refers to the roles they are assigned;
- "maps" refer to the unique identifiers of the roles (role_id);
- "the dates they were handed over" refers to the dates when the roles were assigned (assigned_date);
- "still" implies that the role has not expired, i.e., the expiration date is beyond the current date.

sql:
SELECT location, SINH(latitude) AS sinh_latitude, DENSE_RANK() OVER (ORDER BY latitude) AS latitude_rank
FROM weather_stations
WHERE station_id = 1;
